import React, { useState, useEffect } from 'react';
import axios from 'axios';

const Deposit = () => {
  const [crypto, setCrypto] = useState('USDT');
  const [addresses, setAddresses] = useState({});
  const [amount, setAmount] = useState('');

  useEffect(() => {
    const token = localStorage.getItem('token');
    axios.get('http://localhost:5000/api/deposit/addresses', {
      headers: { Authorization: `Bearer ${token}` }
    })
    .then(res => setAddresses(res.data));
  }, []);

  const handleDeposit = async () => {
    const token = localStorage.getItem('token');
    await axios.post('http://localhost:5000/api/deposit/deposit', { crypto, amount }, {
      headers: { Authorization: `Bearer ${token}` }
    });
    alert('Deposit simulated');
  };

  return (
    <div>
      <select value={crypto} onChange={(e) => setCrypto(e.target.value)}>
        <option value="USDT">USDT</option>
        <option value="USDC">USDC</option>
        <option value="ETH">ETH</option>
      </select>
      <p>Deposit Address: {addresses[crypto]}</p>
      <input type="number" placeholder="Amount" value={amount} onChange={(e) => setAmount(e.target.value)} />
      <button onClick={handleDeposit}>Simulate Deposit</button>
    </div>
  );
};

export default Deposit;
